import{_ as i,o as a,c as e,a2 as t}from"./chunks/framework.BWuWLRhz.js";const c=JSON.parse('{"title":"Services","description":"","frontmatter":{},"headers":[],"relativePath":"app/services.md","filePath":"app/services.md"}'),n={name:"app/services.md"};function h(l,s,r,p,o,d){return a(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="services" tabindex="-1">Services <a class="header-anchor" href="#services" aria-label="Permalink to &quot;Services&quot;">​</a></h1><p>Services are backing data stores — databases, caches, and queues — that run alongside your application containers in an <a href="/app/environments">environment</a>. You declare them in <code>.tragwerk/config.xml</code> and Tragwerk provisions a managed container for each one on the server.</p><h2 id="declaring-services" tabindex="-1">Declaring services <a class="header-anchor" href="#declaring-services" aria-label="Permalink to &quot;Declaring services&quot;">​</a></h2><p>Services live in the XML <code>&lt;services&gt;</code> block. Each service has a name and a runtime (image + version). See the configuration reference for the full schema: <a href="/config/services">Services configuration</a>.</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">services</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">service</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;maindb&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;postgresql:17&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">service</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cache&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;redis:7&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">services</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>To make a service reachable from an application, connect it through a relationship — see <a href="/config/relationships">Relationships</a>:</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">relationships</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">relationship</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;database&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> target</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;maindb&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">relationship</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;redis&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> target</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cache&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">relationships</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>The relationship name becomes the handle your application uses to read the connection details (host, port, credentials) injected into the environment.</p><div class="info custom-block"><p class="custom-block-title">Services stay inside Docker</p><p>Service ports are <strong>not exposed</strong> to the host or the internet. A service is reachable only on the internal Docker network, by the applications in the same environment that declare a relationship to it. There is no public port — only your app containers are reachable from outside (through Traefik). To connect a local client to a database, tunnel in over SSH.</p></div><h2 id="supported-runtimes" tabindex="-1">Supported runtimes <a class="header-anchor" href="#supported-runtimes" aria-label="Permalink to &quot;Supported runtimes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Runtime</th><th>Versions</th></tr></thead><tbody><tr><td>Database</td><td>MariaDB</td><td>10.6, 10.11, 11.4, 11.8</td></tr><tr><td>Database</td><td>MySQL</td><td>8</td></tr><tr><td>Database</td><td>PostgreSQL</td><td>14, 15, 16, 17, 18</td></tr><tr><td>Cache / Queue</td><td>Redis</td><td>6, 7, 8</td></tr><tr><td>Cache / Queue</td><td>Valkey</td><td>8, 9</td></tr></tbody></table><p>The <code>type</code> attribute uses the <code>image:version</code> form, for example <code>mariadb:11.8</code>, <code>mysql:8</code>, <code>postgresql:18</code>, <code>redis:8</code>, or <code>valkey:9</code>.</p><h2 id="live-per-service-status" tabindex="-1">Live per-service status <a class="header-anchor" href="#live-per-service-status" aria-label="Permalink to &quot;Live per-service status&quot;">​</a></h2><p>The Configuration view shows a live status badge for each declared service, polled from the running containers on the server:</p><table tabindex="0"><thead><tr><th>Badge</th><th>Meaning</th></tr></thead><tbody><tr><td>Running</td><td>Container is up and healthy.</td></tr><tr><td>Starting</td><td>Container is running but still in its health check.</td></tr><tr><td>Unhealthy</td><td>Container is running but failing its health check.</td></tr><tr><td>Restarting</td><td>Container is restarting.</td></tr><tr><td>Stopped</td><td>Container exited or died.</td></tr><tr><td>Paused</td><td>The environment is paused.</td></tr><tr><td>Not deployed</td><td>No container exists yet for this service.</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Status is read over SSH and cached briefly (about 15 seconds), so several viewers polling at once share a single connection rather than each opening their own.</p></div><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><p>A PHP app backed by PostgreSQL and Redis:</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">services</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">service</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;db&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;postgresql:17&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">service</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;queue&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;valkey:9&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">services</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">relationships</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">relationship</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;database&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> target</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;db&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">relationship</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cache&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> target</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;queue&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">relationships</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>After the next <a href="/app/deployments">deployment</a>, the Configuration view lists <code>db</code> and <code>queue</code> with their live status badges.</p><h2 id="connecting-to-a-database-from-your-machine" tabindex="-1">Connecting to a database from your machine <a class="header-anchor" href="#connecting-to-a-database-from-your-machine" aria-label="Permalink to &quot;Connecting to a database from your machine&quot;">​</a></h2><p>By default a service has no published port, so you cannot point a client straight at <code>your-server:5432</code>. Either run the client inside the container over SSH, or declare a loopback port and forward it over SSH. Find container names with <code>docker ps</code> on the server — the compose project name looks like <code>tw-&lt;id&gt;-&lt;branch&gt;</code> and the service container like <code>tw-&lt;id&gt;-&lt;branch&gt;-db-1</code>.</p><h3 id="quick-cli-access-no-tunnel" tabindex="-1">Quick CLI access (no tunnel) <a class="header-anchor" href="#quick-cli-access-no-tunnel" aria-label="Permalink to &quot;Quick CLI access (no tunnel)&quot;">​</a></h3><p>For a one-off <code>psql</code> session, run the client inside the container itself:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@your-server</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -it</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tw-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">branc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">h</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">-db-1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> psql</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -U</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span></code></pre></div><h3 id="persistent-loopback-port-config" tabindex="-1">Persistent loopback port (config) <a class="header-anchor" href="#persistent-loopback-port-config" aria-label="Permalink to &quot;Persistent loopback port (config)&quot;">​</a></h3><p>If you regularly attach a local client, declare a <a href="/config/services#service"><code>local-port</code></a> on the service. Tragwerk then publishes it on the server loopback for you — no per-session bridge container:</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">service</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;db&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;postgresql:18&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> local-port</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;55432&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/&gt;</span></span></code></pre></div><p>On the <strong><code>main</code>/<code>master</code> branch</strong> the generated Compose binds the configured port verbatim — <code>127.0.0.1:55432:5432</code> (loopback only, never <code>0.0.0.0</code>). After redeploying, forward it over SSH:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># On your machine: forward your local 5432 to the server loopback port</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 5432:127.0.0.1:55432</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@your-server</span></span></code></pre></div><p>Then connect to <code>localhost:5432</code> with the default <a href="/config/services#default-credentials">credentials</a>. MySQL/MariaDB use internal port <code>3306</code>, Redis/Valkey <code>6379</code>.</p><div class="info custom-block"><p class="custom-block-title">Feature branches get an auto-assigned port</p><p>Because <code>config.xml</code> is shared across branches, a fixed port would collide when two branches run on the same server. So only <strong><code>main</code>/<code>master</code></strong> use the configured <code>local-port</code>. Every other branch binds <code>127.0.0.1::5432</code> — <strong>Docker picks a free loopback port</strong> for it. Find the assigned port with <code>docker ps</code> on the server (look at the <code>127.0.0.1:&lt;port&gt;-&gt;5432/tcp</code> mapping for <code>tw-&lt;id&gt;-&lt;branch&gt;-db-1</code>), then forward that port over SSH.</p></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The published port always binds <code>127.0.0.1</code> on the server, so the service stays reachable only through the SSH tunnel. Tragwerk never publishes a service on <code>0.0.0.0</code> — that would expose your database to the internet, which is exactly what it avoids by default.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/config/services">Services configuration</a></li><li><a href="/config/relationships">Relationships configuration</a></li><li><a href="/app/environments">Environments</a></li><li><a href="/app/logs-containers">Logs &amp; Containers</a></li></ul>`,35)])])}const g=i(n,[["render",h]]);export{c as __pageData,g as default};
